import{_ as e,o as l,c as a,a3 as o}from"./chunks/framework.BTFg6ESq.js";const p=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/getting-started.md","filePath":"user-guide/getting-started.md","lastUpdated":1778233540000}'),r={name:"user-guide/getting-started.md"};function n(s,t,i,d,g,h){return l(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><strong>AIO Hub</strong> 是一款面向 AI 创作者和开发者的桌面工作站，把你日常所需的 AI 对话、内容创作、文档处理等工具整合到一个应用中。你不再需要在多个网页和软件之间来回切换——只需打开 AIO Hub，就能一站式完成从灵感获取到成品输出的全流程。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>💬 LLM 智能对话</strong> — 与 ChatGPT、Claude、Gemini 等多种 AI 模型对话，支持多轮上下文跟踪、智能体切换和长文本压缩</li><li><strong>🧩 30+ 实用工具</strong> — 从图片 OCR 文字识别、视频转写、Git 仓库分析到代码格式化、JSON 格式化，覆盖日常开发与创作的方方面面</li><li><strong>🪟 自由窗口管理</strong> — 任何工具模块的面板都能设置为独立窗口，多任务并行不打架</li><li><strong>🎨 极致视觉体验</strong> — 支持 Windows Mica/Acrylic 毛玻璃特效和动态壁纸，每次打开都是享受</li><li><strong>🔌 开放生态</strong> — 原生支持 OpenAI、Anthropic、Gemini 等主流服务商，兼容 Ollama 本地模型，还有 JavaScript/Rust 插件系统等你来扩展</li></ul><hr><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><blockquote><p>⏱️ 以下步骤只需 5 分钟，跟着走一遍就能开始用 AIO Hub 聊天了。</p></blockquote><h3 id="_1-下载并安装" tabindex="-1">1. 下载并安装 <a class="header-anchor" href="#_1-下载并安装" aria-label="Permalink to &quot;1. 下载并安装&quot;">​</a></h3><p>推荐直接从 GitHub Releases 页面下载发行版，无需配置环境，开箱即用。</p><p><a href="https://github.com/miaotouy/aio-hub/releases/latest" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/v/release/miaotouy/aio-hub?style=for-the-badge&amp;logo=github&amp;label=%E4%B8%8B%E8%BD%BD%E6%AD%A3%E5%BC%8F%E7%89%88%E6%9C%AC" alt="下载正式版本"></a><a href="https://github.com/miaotouy/aio-hub/releases" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/v/release/miaotouy/aio-hub?include_prereleases&amp;style=for-the-badge&amp;logo=github&amp;label=%E4%B8%8B%E8%BD%BD%E9%A2%84%E8%A7%88%E7%89%88&amp;color=yellow" alt="下载预览版"></a></p><blockquote><p>🚀 <strong>提示</strong>：正式版更新较慢，强烈推荐下载 <strong>预览版</strong> (Pre-release) 以体验最新的功能特性与 Bug 修复！</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">平台</th><th style="text-align:left;">格式</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>.exe</code></td><td style="text-align:left;">NSIS 安装包，双击安装即可</td></tr><tr><td style="text-align:left;"><strong>macOS</strong></td><td style="text-align:left;"><code>.dmg</code></td><td style="text-align:left;">支持 Apple Silicon (M系列处理器) 和 Intel</td></tr><tr><td style="text-align:left;"><strong>Linux</strong></td><td style="text-align:left;"><code>.AppImage</code></td><td style="text-align:left;">通用格式，需赋予执行权限</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>.flatpak</code></td><td style="text-align:left;">推荐，沙盒化运行，支持跨发行版</td></tr></tbody></table><p>![下载页面](TODO: 截图-在 GitHub Releases 页面找到最新版本并点击下载)</p><p>安装完成后，双击桌面图标启动 AIO Hub。</p><p>![首次启动界面](TODO: 截图-应用首次启动后的主界面)</p><h3 id="_2-添加你的第一个-llm-服务" tabindex="-1">2. 添加你的第一个 LLM 服务 <a class="header-anchor" href="#_2-添加你的第一个-llm-服务" aria-label="Permalink to &quot;2. 添加你的第一个 LLM 服务&quot;">​</a></h3><p>要跟 AI 对话，你需要先告诉 AIO Hub 用哪个模型。</p><ol><li>点击窗口右上角的 <strong>⚙️ 设置</strong> 图标</li><li>在设置页面中，选择 <strong>LLM AI 服务配置</strong></li><li>点击左侧面板的 <strong>添加服务</strong> 按钮，在弹出的对话框中选择一个服务商预设（如 OpenAI、DeepSeek），或点击右上角&quot;从空白创建&quot;手动配置</li><li>在右侧表单中填入你的 API Key 和服务商地址，配置会自动保存</li></ol><p>![添加 LLM 服务](TODO: 截图-点击添加服务后的配置表单)</p><blockquote><p>💡 <strong>第一次用？</strong> 推荐使用 <a href="https://siliconflow.cn" target="_blank" rel="noreferrer">SiliconFlow</a> 或 <a href="https://platform.deepseek.com" target="_blank" rel="noreferrer">DeepSeek</a> 注册并获取 API Key，两个平台都有免费额度。</p></blockquote><p>添加完成后，你可以在左侧列表里看到刚创建的服务配置，右侧可继续编辑参数。</p><h3 id="_3-开启第一次对话" tabindex="-1">3. 开启第一次对话 <a class="header-anchor" href="#_3-开启第一次对话" aria-label="Permalink to &quot;3. 开启第一次对话&quot;">​</a></h3><ol><li>点击侧边栏顶部的 <strong>🏠 主页</strong> 图标（或默认启动页），在工具网格中找到并点击 <strong>💬 LLM 聊天</strong> 卡片。</li><li><strong>选择或创建智能体</strong>： <ul><li>第一次进入时，你会看到左侧的 <strong>🔮 智能体</strong> 列表。</li><li>点击底部的 <strong>添加智能体</strong> 按钮，选择一个预设（如&quot;全能助手&quot;）或从空白创建。</li><li>在弹出的对话框中，确保选择了你刚才配置的服务和模型，然后点击确定。</li></ul></li><li><strong>新建会话</strong>： <ul><li>选中智能体后，点击右侧侧边栏顶部的 <strong>➕</strong> 按钮（新建对话）。</li></ul></li><li><strong>开始聊天</strong>： <ul><li>在中间底部的输入框里打字，点击发送按钮或按下 <code>Ctrl + Enter</code> 发送消息。</li></ul></li></ol><p>![聊天界面](TODO: 截图-聊天界面，标注出左侧智能体列表、右侧会话列表和底部输入框)</p><p>试试输入：&quot;你好，请用一句话介绍一下你自己&quot;</p><blockquote><p>💡 <strong>小贴士</strong>：输入框默认使用 <code>Ctrl + Enter</code> 发送，<code>Enter</code> 用于换行。你可以在设置中调整此偏好。</p></blockquote><h3 id="_4-探索更多工具" tabindex="-1">4. 探索更多工具 <a class="header-anchor" href="#_4-探索更多工具" aria-label="Permalink to &quot;4. 探索更多工具&quot;">​</a></h3><p>点击侧边栏顶部的 <strong>🏠 主页</strong> 图标回到主页，你会看到平铺展示的所有工具卡片。点击感兴趣的工具即可打开：</p><table tabindex="0"><thead><tr><th style="text-align:left;">工具名称</th><th style="text-align:left;">能干什么</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>智能 OCR</strong></td><td style="text-align:left;">从图片中提取文字，支持多种识别引擎</td></tr><tr><td style="text-align:left;"><strong>音视频转写</strong></td><td style="text-align:left;">把视频/音频/PDF 转成文字</td></tr><tr><td style="text-align:left;"><strong>目录树生成</strong></td><td style="text-align:left;">一键生成项目目录结构</td></tr><tr><td style="text-align:left;"><strong>颜色提取器</strong></td><td style="text-align:left;">从图片中智能提取配色方案</td></tr></tbody></table><p>![工具主页](TODO: 截图-主页平铺显示的所有工具卡片)</p><hr><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="主界面布局" tabindex="-1">主界面布局 <a class="header-anchor" href="#主界面布局" aria-label="Permalink to &quot;主界面布局&quot;">​</a></h3><p>AIO Hub 的主界面分为三个核心区域：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    标题栏                           │</span></span>
<span class="line"><span>├─────────────┬──────────────────────────────────────┤</span></span>
<span class="line"><span>│             │                                      │</span></span>
<span class="line"><span>│  侧边栏     │         主内容区域                     │</span></span>
<span class="line"><span>│  (工具导航)  │     (聊天/工具页面)                   │</span></span>
<span class="line"><span>│             │                                      │</span></span>
<span class="line"><span>│             │                                      │</span></span>
<span class="line"><span>└─────────────┴──────────────────────────────────────┘</span></span></code></pre></div><p>![界面布局标注](TODO: 截图-用箭头/框线标注出三个区域)</p><ul><li><strong>标题栏</strong>：顶部区域，显示应用名称和窗口控制按钮。AIO Hub 使用自定义标题栏，支持更优雅的视觉风格。</li><li><strong>侧边栏</strong>：左侧竖条，作为<strong>运行时标签栏</strong>。它仅显示你当前<strong>已打开</strong>的工具。你可以通过侧边栏在多个任务间快速切换。要打开新工具，请点击顶部的 <strong>🏠 主页</strong> 图标。</li><li><strong>主内容区域</strong>：显示当前选中的工具页面。</li></ul><h3 id="💬-llm-聊天面板" tabindex="-1">💬 LLM 聊天面板 <a class="header-anchor" href="#💬-llm-聊天面板" aria-label="Permalink to &quot;💬 LLM 聊天面板&quot;">​</a></h3><p>聊天是 AIO Hub 的旗舰功能，不仅是一个简单的对话窗口。</p><h4 id="关键参数说明" tabindex="-1">关键参数说明 <a class="header-anchor" href="#关键参数说明" aria-label="Permalink to &quot;关键参数说明&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">位置</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>模型选择</strong></td><td style="text-align:left;">聊天窗口右上角</td><td style="text-align:left;">选择当前要使用的 AI 模型。每个 LLM 服务下可以配置多个模型</td></tr><tr><td style="text-align:left;"><strong>智能体选择</strong></td><td style="text-align:left;">模型选择器旁边</td><td style="text-align:left;">切换不同的 AI &quot;人设&quot;。你可以创建多个智能体，每个有独立的设定和知识库</td></tr><tr><td style="text-align:left;"><strong>上下文长度</strong></td><td style="text-align:left;">聊天窗口顶部/底部</td><td style="text-align:left;">显示当前对话消耗的 Token 数量。蓝色条表示已用比例</td></tr><tr><td style="text-align:left;"><strong>输入模式</strong></td><td style="text-align:left;">输入框左侧图标</td><td style="text-align:left;">切换纯文本 / 带格式 / 附件模式</td></tr></tbody></table><p>![聊天面板参数标注](TODO: 截图-在聊天界面上标注出上述参数位置)</p><h4 id="常用操作" tabindex="-1">常用操作 <a class="header-anchor" href="#常用操作" aria-label="Permalink to &quot;常用操作&quot;">​</a></h4><ul><li><strong>发送消息</strong>：输入文字后按 <code>Ctrl + Enter</code></li><li><strong>换行</strong>：直接按 <code>Enter</code></li><li><strong>上传附件</strong>：点击输入框左侧的 📎 图标，或直接拖拽文件到输入区域</li><li><strong>查看上下文</strong>：点击 Token 数字，可以展开查看发送给 AI 的完整 Prompt</li><li><strong>重启对话</strong>：点击聊天窗口顶部的 🗑️ 图标清空当前对话</li></ul><h3 id="🛠️-工具面板" tabindex="-1">🛠️ 工具面板 <a class="header-anchor" href="#🛠️-工具面板" aria-label="Permalink to &quot;🛠️ 工具面板&quot;">​</a></h3><p>AIO Hub 内置了 30+ 工具，按功能分为以下几类：</p><h4 id="多媒体创作" tabindex="-1">多媒体创作 <a class="header-anchor" href="#多媒体创作" aria-label="Permalink to &quot;多媒体创作&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>媒体生成器</strong></td><td style="text-align:left;">一站式生成图像、音频、视频，支持任务队列和分支管理</td></tr><tr><td style="text-align:left;"><strong>音视频转写</strong></td><td style="text-align:left;">把视频、音频、PDF 文件转成文字，支持多模型驱动</td></tr><tr><td style="text-align:left;"><strong>FFmpeg 助手</strong></td><td style="text-align:left;">视频压缩、格式转换、批量处理，基于 Rust 高性能后端</td></tr></tbody></table><h4 id="开发者生产力" tabindex="-1">开发者生产力 <a class="header-anchor" href="#开发者生产力" aria-label="Permalink to &quot;开发者生产力&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Git 仓库分析器</strong></td><td style="text-align:left;">分析 Git 仓库的贡献者、提交频率、分支结构，秒开大型仓库</td></tr><tr><td style="text-align:left;"><strong>智能 OCR</strong></td><td style="text-align:left;">从图片中提取文字，支持多引擎（AI 视觉识别 / Windows 原生 / Tesseract）</td></tr><tr><td style="text-align:left;"><strong>正则表达式应用器</strong></td><td style="text-align:left;">编写正则替换规则，实时预览效果，支持批量处理文件</td></tr><tr><td style="text-align:left;"><strong>Token 计算器</strong></td><td style="text-align:left;">精确计算不同模型的 Token 消耗，支持图片 Token 分析</td></tr></tbody></table><h4 id="系统与文件管理" tabindex="-1">系统与文件管理 <a class="header-anchor" href="#系统与文件管理" aria-label="Permalink to &quot;系统与文件管理&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>资产管理器</strong></td><td style="text-align:left;">集中管理所有工具产生的图片、文档和转写记录，自动去重</td></tr><tr><td style="text-align:left;"><strong>目录清理</strong></td><td style="text-align:left;">按规则扫描并清理无用文件，支持安全回收站模式</td></tr><tr><td style="text-align:left;"><strong>符号链接搬迁</strong></td><td style="text-align:left;">把文件&quot;搬&quot;到其他目录，支持符号链接和硬链接</td></tr><tr><td style="text-align:left;"><strong>目录树生成</strong></td><td style="text-align:left;">一键生成漂亮的目录结构树，支持 .gitignore 规则</td></tr></tbody></table><h4 id="日常工具" tabindex="-1">日常工具 <a class="header-anchor" href="#日常工具" aria-label="Permalink to &quot;日常工具&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>JSON 格式化</strong></td><td style="text-align:left;">格式化 / 压缩 / 校验 JSON 和 YAML</td></tr><tr><td style="text-align:left;"><strong>文本差异对比</strong></td><td style="text-align:left;">对比两段文本的差异，支持文件拖拽</td></tr><tr><td style="text-align:left;"><strong>代码格式化</strong></td><td style="text-align:left;">基于 Prettier 引擎的多语言代码格式化</td></tr><tr><td style="text-align:left;"><strong>颜色提取</strong></td><td style="text-align:left;">从图片中提取配色方案，支持屏幕取色</td></tr><tr><td style="text-align:left;"><strong>API 测试器</strong></td><td style="text-align:left;">发送 HTTP 请求并查看响应，支持 SSE 流式响应</td></tr></tbody></table><p>![工具详情页](TODO: 截图-打开某个工具（如 JSON 格式化）后的界面)</p><h3 id="⚙️-设置中心" tabindex="-1">⚙️ 设置中心 <a class="header-anchor" href="#⚙️-设置中心" aria-label="Permalink to &quot;⚙️ 设置中心&quot;">​</a></h3><p>点击窗口右上角的 ⚙️ 图标进入设置。</p><h4 id="llm-服务配置" tabindex="-1">LLM 服务配置 <a class="header-anchor" href="#llm-服务配置" aria-label="Permalink to &quot;LLM 服务配置&quot;">​</a></h4><ul><li><strong>添加服务</strong>：从预设模板快速创建配置，或从空白开始手动填写服务商名称、API 地址和 Key</li><li><strong>模型管理</strong>：配置该服务下可用的模型列表，设置默认模型</li><li><strong>连接测试</strong>：点击&quot;测试连接&quot;验证配置是否正确</li></ul><h4 id="外观设置" tabindex="-1">外观设置 <a class="header-anchor" href="#外观设置" aria-label="Permalink to &quot;外观设置&quot;">​</a></h4><ul><li><strong>主题模式</strong>：跟随系统 / 浅色 / 深色</li><li><strong>界面质感</strong>：调整透明度、毛玻璃强度、边框样式</li><li><strong>动态壁纸</strong>：选择内置壁纸或自定义图片/视频轮播</li></ul><hr><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><p>掌握了基础操作后，这些高阶技巧能让你的效率更上一层楼。</p><h3 id="🪟-组件分离拖拽" tabindex="-1">🪟 组件分离拖拽 <a class="header-anchor" href="#🪟-组件分离拖拽" aria-label="Permalink to &quot;🪟 组件分离拖拽&quot;">​</a></h3><p>AIO Hub 的多数面板都支持拖拽为独立窗口——这是它最独特的功能之一。</p><p><strong>场景：边聊天边看文档</strong></p><ol><li>打开 LLM 聊天面板</li><li>把鼠标移到聊天面板的标题栏</li><li>按住标题栏拖拽到主窗口之外</li></ol><p>![拖拽分离](TODO: 截图-聊天面板被拖拽出主窗口的瞬间)</p><p>聊天面板会变成一个独立的悬浮窗口，你可以把它拖到另一个屏幕。这时再在主窗口里打开其他工具——两个窗口互不干扰，状态同步更新。</p><p><strong>可分离的面板</strong>：聊天输入框、对话区域、媒体生成器、JSON 格式化等几乎所有工具面板都支持。</p><h3 id="⌨️-快捷键参考" tabindex="-1">⌨️ 快捷键参考 <a class="header-anchor" href="#⌨️-快捷键参考" aria-label="Permalink to &quot;⌨️ 快捷键参考&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">快捷键</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Ctrl + Enter</code></td><td style="text-align:left;">聊天发送消息</td></tr><tr><td style="text-align:left;"><code>Esc</code></td><td style="text-align:left;">取消正在进行的拖拽分离操作</td></tr></tbody></table><blockquote><p>💡 <strong>提示</strong>：在代码编辑器（如 JSON 格式化、文本对比）中，你可以使用 Monaco Editor 内置的快捷键，例如 <code>Ctrl + F</code> 进行搜索。</p></blockquote><h3 id="🎨-深度主题定制" tabindex="-1">🎨 深度主题定制 <a class="header-anchor" href="#🎨-深度主题定制" aria-label="Permalink to &quot;🎨 深度主题定制&quot;">​</a></h3><p>如果默认的外观还不能让你满意，可以试试：</p><ol><li><strong>动态壁纸</strong>：在设置中开启&quot;动态壁纸&quot;，选择内置壁纸或添加自己的图片/视频</li><li><strong>CSS 编辑器</strong>：在设置 → 外观 → CSS 编辑器中直接写 CSS 覆盖样式</li><li><strong>样式宏</strong>：利用 CSS 变量快速调整全局配色（参考 <a href="./../user-guide/tools/llm-chat/css-variables-guide">CSS 变量宏指南</a>）</li></ol><h3 id="🔌-使用插件扩展功能" tabindex="-1">🔌 使用插件扩展功能 <a class="header-anchor" href="#🔌-使用插件扩展功能" aria-label="Permalink to &quot;🔌 使用插件扩展功能&quot;">​</a></h3><p>AIO Hub 支持三种插件类型：</p><ul><li><strong>JavaScript 插件</strong>：轻量级 UI 扩展，即写即用。放在 <code>plugins/</code> 目录下即可自动加载</li><li><strong>Native 插件 (Rust)</strong>：高性能后端扩展，通过 DLL 动态加载</li><li><strong>Sidecar 插件</strong>：任意语言编写的独立进程插件</li></ul><blockquote><p>插件开发教程请参考 <a href="./../guide/plugin-development-guide">插件开发指南</a>。</p></blockquote><h3 id="🌐-多模型协同" tabindex="-1">🌐 多模型协同 <a class="header-anchor" href="#🌐-多模型协同" aria-label="Permalink to &quot;🌐 多模型协同&quot;">​</a></h3><p>你在同一段对话中可以随时切换不同模型：</p><ol><li>先用 DeepSeek 生成代码框架</li><li>切换到 Claude 进行代码审查</li><li>切换到 Gemini 做多模态分析</li></ol><p>每个模型看到的都是完整的对话历史，切换无缝衔接。</p><p>![模型切换](TODO: 截图-在聊天中进行模型切换操作)</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q1-为什么发送消息后没有回复" tabindex="-1">Q1：为什么发送消息后没有回复？ <a class="header-anchor" href="#q1-为什么发送消息后没有回复" aria-label="Permalink to &quot;Q1：为什么发送消息后没有回复？&quot;">​</a></h3><p>可能的原因和解决方法：</p><ol><li><strong>LLM 服务配置有误</strong> — 去设置中点击&quot;测试连接&quot;确认 API Key 和地址填写正确</li><li><strong>网络问题</strong> — 如果使用本地模型（Ollama），确认服务是否在运行；如果使用云端 API，确认网络可以访问</li><li><strong>模型选择不对</strong> — 确认聊天窗口右上角已选中了正确的模型</li></ol><h3 id="q2-如何添加自己的-api-key" tabindex="-1">Q2：如何添加自己的 API Key？ <a class="header-anchor" href="#q2-如何添加自己的-api-key" aria-label="Permalink to &quot;Q2：如何添加自己的 API Key？&quot;">​</a></h3><p>进入 <strong>设置 → LLM 服务</strong>，点击 <strong>添加服务</strong>：</p><ul><li><strong>服务商</strong>：选择预设的 OpenAI / Anthropic / Gemini / DeepSeek / SiliconFlow 等</li><li><strong>API Key</strong>：从对应平台复制并粘贴</li><li><strong>模型列表</strong>：系统会自动拉取可用模型，也可以手动添加</li></ul><p>如果列表中找不到你的服务商，可以选择&quot;自定义&quot;，手动填入 API 地址。</p><h3 id="q3-窗口分离后怎么恢复" tabindex="-1">Q3：窗口分离后怎么恢复？ <a class="header-anchor" href="#q3-窗口分离后怎么恢复" aria-label="Permalink to &quot;Q3：窗口分离后怎么恢复？&quot;">​</a></h3><ul><li><strong>拖拽回去</strong>：把分离窗口的标题栏拖回主窗口区域，它会自动吸附合并</li><li><strong>关闭分离窗口</strong>：点击分离窗口的关闭按钮，它会自动回到主窗口中原来的位置</li></ul><blockquote><p>所有分离窗口的位置和大小都会被自动记住，下次启动应用时会自动恢复。</p></blockquote><h3 id="q4-应用卡顿或崩溃怎么办" tabindex="-1">Q4：应用卡顿或崩溃怎么办？ <a class="header-anchor" href="#q4-应用卡顿或崩溃怎么办" aria-label="Permalink to &quot;Q4：应用卡顿或崩溃怎么办？&quot;">​</a></h3><ol><li><strong>更新到最新版本</strong>：预览版修复了许多稳定性问题</li><li><strong>清理缓存</strong>：关闭应用后，删除 <code>%APPDATA%\\com.mty.aiohub\\cache</code> 目录（Windows）</li><li><strong>查看日志</strong>：日志文件位于 <code>%APPDATA%\\com.mty.aiohub\\logs\\</code>，可用于排查具体原因</li><li><strong>反馈问题</strong>：在 GitHub Issues 中提交 Bug 报告，附上日志文件</li></ol><h3 id="q5-如何卸载-aio-hub" tabindex="-1">Q5：如何卸载 AIO Hub？ <a class="header-anchor" href="#q5-如何卸载-aio-hub" aria-label="Permalink to &quot;Q5：如何卸载 AIO Hub？&quot;">​</a></h3><ul><li><strong>Windows</strong>：在&quot;设置 → 应用&quot;中找到 AIO Hub 并卸载，或使用安装目录下的卸载程序</li><li><strong>macOS</strong>：将应用从&quot;应用程序&quot;文件夹拖入废纸篓</li><li><strong>Linux</strong>：如果是通过包管理器安装，使用对应的卸载命令；如果是 AppImage，直接删除文件即可</li></ul><blockquote><p>卸载后，配置文件和数据（<code>%APPDATA%\\com.mty.aiohub</code>）默认会保留，如果需要彻底清除，请手动删除该目录。</p></blockquote><hr><blockquote><p>下一步：想了解具体工具的使用方法？请参考 <a href="./tools/">工具总览</a>。</p></blockquote>`,106)])])}const c=e(r,[["render",n]]);export{p as __pageData,c as default};
